    {
      "path": "src/modules/members/service.js",
      "content": "const { sendError } = require('../../lib/errors');

const addMemberToProject = (projects, projectId, userId, role) => {
  const project = projects[projectId];
  if (!project) {
    return null;
  }
  if (project.members.some(member => member.userId === userId)) {
    return null;
  }
  project.members.push({ userId, role });
  return project;
};

module.exports = { addMemberToProject };
