      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

const createTaskInProject = (projects, projectId, description) => {
  const project = projects[projectId];
  if (!project) {
    return null;
  }
  const taskId = randomUUID();
  const task = { id: taskId, description, status: 'todo' };
  project.tasks.push(task);
  return task;
};

const updateTaskStatusInProject = (projects, projectId, taskId, newStatus) => {
  const project = projects[projectId];
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task || !['todo', 'done'].includes(newStatus)) {
    return null;
  }
  task.status = newStatus;
  return task;
};

module.exports = { createTaskInProject, updateTaskStatusInProject };
