      "path": "src/modules/comments/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

const addCommentToTask = (projects, projectId, taskId, message) => {
  const project = projects[projectId];
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  const commentId = randomUUID();
  const comment = { id: commentId, message };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
};

module.exports = { addCommentToTask };
